def find_maximal_cliques(graph):
    cliques = []

    all_vertices = set(graph.keys())
    for u in graph:
        all_vertices.update(graph[u])

    def get_neighbors(vertex):
        return graph.get(vertex, set())

    def _bron_kerbosch(R, P, X):
        if not P and not X:
            if R:
                cliques.append(frozenset(R))
            return

        pivot_union = P.union(X)
        if not pivot_union:
            return

        u = None
        max_neighbors_in_P = -1
        for vertex in pivot_union:
            neighbors_in_P_count = len(get_neighbors(vertex).intersection(P))
            if neighbors_in_P_count > max_neighbors_in_P:
                max_neighbors_in_P = neighbors_in_P_count
                u = vertex

        P_minus_N_u_original = P - get_neighbors(u)

        for v in list(P_minus_N_u_original):
            _bron_kerbosch(R.union({v}), P.intersection(get_neighbors(v)), X.intersection(get_neighbors(v)))
            P.remove(v)
            X.add(v)

    _bron_kerbosch(set(), all_vertices, set())
    return cliques
